        // Let's see if we have timezone indicator or not...
        if (hasTimeZone(dateStr)) {
            c = dateStr.charAt(len-3);
            if (c == ':') { // remove optional colon
                // remove colon
                StringBuilder sb = new StringBuilder(dateStr);
                sb.delete(len-3, len-2);
                dateStr = sb.toString();
            } else if (c == '+' || c == '-') { // missing minutes
                // let's just append '00'
                dateStr += "00";
            }
            // Milliseconds partial or missing; and even seconds are optional
            len = dateStr.length();
            // Find the position of the decimal point if it exists
            int dotIndex = dateStr.lastIndexOf('.');
            int tzStartIndex = len - 5; // timezone offset starts 5 chars from end

            if (dotIndex > 0 && dotIndex < tzStartIndex) {
                // Partial milliseconds exist; pad to 3 digits
                int millisDigits = tzStartIndex - dotIndex - 1;
                if (millisDigits < 3) {
                    StringBuilder sb = new StringBuilder(dateStr);
                    for (int i = millisDigits; i < 3; i++) {
                        sb.insert(tzStartIndex, '0');
                    }
                    dateStr = sb.toString();
                }
            } else if (dotIndex == -1) {
                // No milliseconds at all
                // Check if seconds are missing
                c = dateStr.charAt(len-9);
                if (Character.isDigit(c)) {
                    // Seconds present, add milliseconds
                    StringBuilder sb = new StringBuilder(dateStr);
                    sb.insert(len-5, ".000");
                    dateStr = sb.toString();
                } else {
                    // Seconds missing, add both seconds and milliseconds
                    StringBuilder sb = new StringBuilder(dateStr);
                    sb.insert(len-5, ":00.000");
                    dateStr = sb.toString();
                }
            }
            df = _formatISO8601;
            if (_formatISO8601 == null) {
                df = _formatISO8601 = _cloneFormat(DATE_FORMAT_ISO8601, DATE_FORMAT_STR_ISO8601, _timezone, _locale);
            }
        } else {
            // If not, plain date. Easiest to just patch 'Z' in the end?
            StringBuilder sb = new StringBuilder(dateStr);
            // And possible also millisecond part if missing
            int timeLen = len - dateStr.lastIndexOf('T') - 1;
            if (timeLen <= 8) {
                    sb.append(".000");
            }
            sb.append('Z');
            dateStr = sb.toString();
            df = _formatISO8601_z;
            if (df == null) {
