            String pkgName = com.fasterxml.jackson.databind.util.ClassUtil.getPackageName(cls);
            if (pkgName != null) {
                sb.append(pkgName);
                sb.append('.');
            }
            String className = cls.getName();
            if (pkgName != null) {
                className = className.substring(pkgName.length() + 1);
